  root: {
    display:"flex", flexDirection:"column", height:"100vh",
    background:"linear-gradient(160deg, #fdf6ff 0%, #f0e8ff 50%, #fce8f3 100%)",
    fontFamily:"'Zen Maru Gothic', 'Kosugi Maru', sans-serif",
    position:"relative", overflow:"hidden",
  },
