  bgStar: {
    position:"absolute", fontSize:18, opacity:0.12,
    animation:"sparkle 3s ease-in-out infinite",
  },
  header: {
    display:"flex", alignItems:"center", justifyContent:"space-between",
    padding:"10px 20px", flexShrink:0, zIndex:10,
    background:"rgba(255,255,255,0.7)", backdropFilter:"blur(12px)",
    borderBottom:"1.5px solid #e8d5ff",
  },
  headerLeft: { display:"flex", alignItems:"center", gap:10 },
  avatarSmall: { width:56, height:56, flexShrink:0 },
  headerName: { fontWeight:700, fontSize:16, color:"#7c5cbf" },
  headerSub: { fontSize:11, color:"#b09ad0", marginTop:1 },
  onlineBadge: { fontSize:12, color:"#7c5cbf", background:"#f0e8ff", padding:"4px 12px", borderRadius:20, border:"1px solid #d4b8f0" },
  chatArea: {
    flex:1, overflowY:"auto", padding:"20px 16px",
    display:"flex", flexDirection:"column", gap:14, zIndex:1,
  },
  welcome: { display:"flex", flexDirection:"column", alignItems:"center", gap:20, paddingTop:10 },
  characterWrap: { display:"flex", alignItems:"flex-end", gap:12 },
